store = {"C001": {"id": "C001", "region": "Lima"}}

def get_entity(store, entity_id):
    if entity_id in store:
        return 200, store[entity_id]
    return 404, {"error": "not_found"}

print(get_entity(store, "C001"))
print(get_entity(store, "C999"))

def parse_entity(payload):
    if not isinstance(payload, dict):
        raise ValueError("payload")
    if "id" not in payload or "region" not in payload:
        raise ValueError("missing keys")
    return {"id": payload["id"], "region": payload["region"]}

print(parse_entity({"id": "C001", "region": "Lima", "extra": 1}))

STATUS_ACTION = {
    200: "use_body",
    404: "missing",
    429: "retry",
    500: "retry",
    400: "fix_client",
}
for s in [200, 404, 429, 400, 500]:
    print(s, STATUS_ACTION[s])

def fetch(timeout_s, cost_s):
    try:
        if cost_s > timeout_s:
            raise TimeoutError("timeout")
        return "ok"
    except TimeoutError:
        return "timeout"

print(fetch(2, 1), "|", fetch(1, 3))

def collect_all(api):
    page = 1
    out = []
    while True:
        data = api(page)
        out.extend(data["items"])
        if data.get("next") is None:
            break
        page = data["next"]
    return out

def api(page):
    if page == 1:
        return {"items": ["a", "b"], "next": 2}
    return {"items": ["c"], "next": None}

print(collect_all(api))

def should_retry(status):
    return status in (429, 503)

for s in (400, 404, 429, 503, 200):
    print(s, should_retry(s))

def require_token(env):
    tok = env.get("API_TOKEN")
    if not tok:
        raise ValueError("API_TOKEN missing")
    return tok

print(require_token({"API_TOKEN": "abc"}))
try:
    require_token({})
except ValueError as e:
    print(e)

class Cache:
    def __init__(self):
        self._d = {}
    def get(self, url):
        if url in self._d:
            return self._d[url], True
        return None, False
    def set(self, url, body):
        self._d[url] = body

c = Cache()
c.set("u", {"ok": True})
print(c.get("u"), "|", c.get("v"))

def min_provenance(url, status, cache_hit):
    return {
        "source_url": url,
        "fetched_at": "2026-07-20T00:00:00Z",
        "status_code": status,
        "cache_hit": cache_hit,
    }

print(min_provenance("https://example.com", 200, False))

def assert_keys(payload, required):
    missing = sorted(k for k in required if k not in payload)
    if missing:
        raise AssertionError(f"missing keys: {missing}")
    print("ok")

assert_keys({"lat": 1, "lon": 2}, ["lat", "lon"])
try:
    assert_keys({"lat": 1}, ["lat", "lon"])
except AssertionError as e:
    print(e)

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return local_body, "offline"
    if status == 200:
        return {"online": True}, "live"
    return None, "error"

print(fetch_with_fallback(500, {"local": 1}))
print(fetch_with_fallback(200, {"local": 1}))

matrix = {
