print("True", matrix[("online", True)], "|", "False", matrix[("online", False)])

import re

def normalize_address(s: str) -> str:
    return re.sub(r"\s+", " ", s.strip())

print(repr(normalize_address('  Jr.  de  la  Unión  100 ')))

class MockGeocoder:
    def geocode(self, city):
        data = {"Lima": {"lat": -12.0464, "lon": -77.0428}}
        return data.get(city)

g = MockGeocoder()
print(g.geocode("Lima")["lat"], "|", g.geocode("Arequipa"))

def allowed_for_public_geocoder(payload: dict) -> bool:
    banned = {"document_id", "bank_account", "password", "api_token"}
    if banned & set(payload):
        return False
    return set(payload).issubset({"address", "city", "country", "lat", "lon"})

print(allowed_for_public_geocoder({"city": "Lima"}))
print(allowed_for_public_geocoder({"document_id": "X", "city": "Lima"}))

def valid_lat_lon(lat, lon):
    return -90 <= lat <= 90 and -180 <= lon <= 180

for pair in [(0, 0), (91, 0), (0, 181), (-12.04, -77.04)]:
    print(pair, valid_lat_lon(*pair))

